def get_large_manuscript(target_chars: int = 60000) -> str:
    parts: list[str] = []
    parts.append(f"# {_TITLE}\n")
    parts.append(f"{_ABSTRACT}\n")

    for heading, paragraphs in _SECTIONS:
        parts.append(f"\n## {heading}\n")
        for p in paragraphs:
            parts.append(p.strip() + "\n")

    parts.append(f"\n{_BIBLIOGRAPHY}\n")

    base = "\n".join(parts)
    current_len = len(base)

    if current_len >= target_chars:
        return base

    expansion_idx = 0
    section_idx = 0
    while current_len < target_chars:
        para = _EXPANSION_PARAGRAPHS[expansion_idx % len(_EXPANSION_PARAGRAPHS)]
        variant = para.strip()
        if expansion_idx >= len(_EXPANSION_PARAGRAPHS):
            variant = variant + f" [Ср. аналогичные наблюдения в: {expansion_idx + 10}]."
        section_name = _SECTIONS[section_idx % len(_SECTIONS)][0]
        insert_marker = f"\n## {section_name}\n"
        if insert_marker in base:
            idx = base.index(insert_marker) + len(insert_marker)
            base = base[:idx] + "\n" + variant + "\n" + base[idx:]
        else:
            base += "\n" + variant + "\n"
        current_len = len(base)
        expansion_idx += 1
        section_idx += 1

    return base


def get_medium_manuscript() -> str:
    return get_large_manuscript(target_chars=20000)
